INSERT INTO initiative_templates (id, name, category, description, evidence_base, target_outcomes, typical_timeline, resources_needed, active_ingredients, decision_brief_template) VALUES
('f6dd5c7b-d138-4c7f-840a-e3d5b4236afb', 'Intensive Literacy Intervention', 'Intervention', 'High-dosage, small-group or 1:1 intervention focusing on decoding, fluency, and comprehension for students significantly below grade level.', 'Evidence from targeted intervention studies shows accelerated growth when delivered with sufficient intensity and fidelity.', ARRAY['Accelerate reading growth','Close skill gaps','Improve comprehension']::text[], 'Daily 30–45 minute sessions for 12–24 weeks', ARRAY['Intervention materials','Progress monitoring tools','Training & coaching']::text[], '[{"description": "Pinpoint skill deficits to target instruction.", "is_core": true, "name": "Diagnostic placement"}, {"description": "Daily sessions with explicit instruction.", "is_core": true, "name": "High-dosage small group"}, {"description": "Spiral practice to solidify learning.", "is_core": true, "name": "Cumulative review & practice"}, {"description": "Weekly tracking to adjust instruction.", "is_core": true, "name": "Frequent progress monitoring"}]'::jsonb, '{"lagging_indicators": ["Standardized reading scores", "Grade-level comprehension"], "leading_indicators": ["Attendance", "Lesson completion", "Words correct per minute"], "measurement_timeline": "Weekly PM; 6\u20138 week formal reviews.", "problem_statement": "Persistent reading deficits despite core instruction.", "target_group": "Students >1.5 SD below benchmark."}'::jsonb),
('6f360536-de9c-49d9-8dcb-10f21cb2f840', 'PBIS (Positive Behavioral Interventions and Supports)', 'Behavior', 'A multi-tiered framework emphasizing proactive strategies for defining, teaching, and supporting appropriate student behaviors.', 'Extensive evidence across hundreds of schools showing reductions in office discipline referrals and improvements in climate.', ARRAY['Reduce office discipline referrals','Increase instructional time','Improve school climate']::text[], 'School-wide rollout over 6–12 months with continuous data cycles', ARRAY['Behavior matrix posters','Acknowledgement system','Referral data tracker']::text[], '[{"description": "Define 3\u20135 positively stated expectations across settings.", "is_core": true, "name": "Behavior expectations matrix"}, {"description": "Direct instruction and practice of expected behaviors.", "is_core": true, "name": "Explicit teaching of expectations"}, {"description": "Consistent reinforcement of expected behaviors.", "is_core": true, "name": "Acknowledgement system"}, {"description": "Monthly review of ODRs to target supports.", "is_core": true, "name": "Data-based problem solving"}, {"description": "Active supervision, precorrections, and calm responses.", "is_core": false, "name": "Classroom routines & corrections"}]'::jsonb, '{"lagging_indicators": ["ODR per 100 students", "Suspension rates"], "leading_indicators": ["Tickets issued per week", "Lesson delivery rate"], "measurement_timeline": "Monthly ODR review; quarterly climate surveys.", "problem_statement": "High ODR rates reduce instructional time.", "target_group": "All students (Tier 1), with Tier 2 supports as needed."}'::jsonb),
('0a8b685d-70e8-4882-90e0-4c413bb15dc4', 'MTSS/RTI Framework', 'Framework', 'Tiered system providing increasing levels of support matched to student need using screening, progress monitoring, and data-based decision making.', 'Strong evidence for improved outcomes when high-quality core instruction, screening, and targeted interventions are implemented with fidelity.', ARRAY['Improve universal screening coverage','Increase responsiveness to interventions','Reduce special education referrals']::text[], 'Establish within a semester; refine continuously through data cycles', ARRAY['Screening tools','Progress monitoring probes','Intervention menu']::text[], '[{"description": "At least 3x/year with high coverage.", "is_core": true, "name": "Universal screening"}, {"description": "Evidence-based options matched to need.", "is_core": true, "name": "Tiered intervention menu"}, {"description": "Regular team review and instructional adjustments.", "is_core": true, "name": "Data meetings"}, {"description": "Weekly or biweekly measures to track growth.", "is_core": true, "name": "Progress monitoring"}, {"description": "Fidelity checks and refinements.", "is_core": false, "name": "Check & adjust"}]'::jsonb, '{"lagging_indicators": ["Growth percentile", "Referral rates"], "leading_indicators": ["PM completion rate", "Intervention dosage"], "measurement_timeline": "Every 4\u20136 weeks in MTSS meetings.", "problem_statement": "Inconsistent response to interventions across grades.", "target_group": "Students identified via screening and PM data."}'::jsonb),
('a1bb3883-6b97-472c-ac49-7b984417480c', 'Second Step Social-Emotional Learning', 'SEL', 'A structured SEL curriculum building self-management, relationship skills, and responsible decision-making.', 'Multiple randomized trials report improvements in prosocial behavior and reductions in problem behavior.', ARRAY['Increase prosocial behaviors','Improve self-regulation','Reduce disruptive incidents']::text[], 'Weekly lessons over 20–30 weeks with embedded practice', ARRAY['Lesson kits','Family engagement letters','Implementation guide']::text[], '[{"description": "Scripted lessons with modeling and practice.", "is_core": true, "name": "Weekly explicit SEL lessons"}, {"description": "Daily prompts to generalize skills.", "is_core": true, "name": "Embedded practice routines"}, {"description": "Acknowledge use of SEL skills; student reflection.", "is_core": true, "name": "Reinforcement & reflection"}, {"description": "Send home practice activities.", "is_core": false, "name": "Family connection"}]'::jsonb, '{"lagging_indicators": ["Incident rates", "Prosocial behavior ratings"], "leading_indicators": ["Lesson completion", "Teacher-reported use"], "measurement_timeline": "Monthly behavior dashboards; quarterly surveys.", "problem_statement": "Students struggle with self-regulation and peer conflict.", "target_group": "All students with targeted supports for some."}'::jsonb),
('e6cb4010-7052-4f28-b513-fc8953b4f3df', 'Structured Literacy Program', 'Literacy', 'Systematic, explicit instruction in phonemic awareness, phonics, fluency, vocabulary, and comprehension aligned to the science of reading.', 'Strong evidence from meta-analyses (e.g., National Reading Panel, IES WWC) showing improved early decoding and long-term reading outcomes.', ARRAY['Improve decoding accuracy','Increase reading fluency','Boost comprehension on grade-level texts']::text[], 'Core implementation over 12–24 weeks with ongoing progress monitoring', ARRAY['Tiered materials set','Decodable texts','Screeners & progress monitors']::text[], '[{"description": "Daily, systematic instruction of sound-spelling patterns with cumulative review.", "is_core": true, "name": "Explicit phonics routines"}, {"description": "Oral blending, segmenting, and manipulation activities.", "is_core": true, "name": "Phonemic awareness practice"}, {"description": "Controlled texts aligned to taught patterns for fluency.", "is_core": true, "name": "Decodable text practice"}, {"description": "Immediate corrective feedback with guided practice.", "is_core": true, "name": "Error correction routine"}, {"description": "Pre-teach key vocabulary and build knowledge.", "is_core": false, "name": "Vocabulary and background"}]'::jsonb, '{"lagging_indicators": ["DIBELS/Acadience composite score", "Reading comprehension"], "leading_indicators": ["Lesson completion fidelity", "Weekly word reading accuracy"], "measurement_timeline": "Every 2\u20133 weeks using CBM measures.", "problem_statement": "Early readers show below-benchmark decoding and fluency.", "target_group": "K\u20132 students below benchmark on universal screening."}'::jsonb)
